from queryweave.parser.lexer import Lexer, Token, TokenStream, TokenType
from queryweave.utils.errors import ParseError


Statement = SelectStmt | UnionStmt | InsertStmt | UpdateStmt | DeleteStmt | CreateTableStmt | DropTableStmt


class Parser:
    """Parses lexer tokens into QueryWeave AST nodes."""

    _AGGREGATES = {"COUNT", "SUM", "AVG", "MIN", "MAX"}
    _CLAUSE_STARTERS = {
        TokenType.FROM,
        TokenType.WHERE,
        TokenType.GROUP_BY,
        TokenType.GROUP,
        TokenType.HAVING,
        TokenType.ORDER_BY,
        TokenType.ORDER,
        TokenType.LIMIT,
        TokenType.OFFSET,
        TokenType.UNION,
        TokenType.SEMICOLON,
        TokenType.EOF,
    }

    def __init__(self, source: str | Lexer | TokenStream | list[Token]) -> None:
        if isinstance(source, TokenStream):
            self.tokens = source
        elif isinstance(source, Lexer):
            self.tokens = TokenStream(source.tokenize())
        elif isinstance(source, str):
            self.tokens = TokenStream(Lexer(source).tokenize())
        else:
            self.tokens = TokenStream(source)

    def parse(self) -> Statement:
        """Parse a complete statement and require all tokens to be consumed."""
        statement = self.parse_statement()
        while self.tokens.match(TokenType.SEMICOLON):
            pass
        if not self.tokens.at_end():
            self._error_current("Unexpected token after statement")
        return statement

    def parse_statement(self) -> Statement:
        """Parse a single SQL statement."""
        if self.tokens.check(TokenType.SELECT):
            return self.parse_query()
        if self.tokens.check(TokenType.INSERT):
            return self.parse_insert()
        if self.tokens.check(TokenType.UPDATE):
            return self.parse_update()
        if self.tokens.check(TokenType.DELETE):
            return self.parse_delete()
        if self.tokens.check(TokenType.CREATE):
            return self.parse_create()
        if self.tokens.check(TokenType.DROP):
            return self.parse_drop()
        self._error_current("Expected statement")

    def parse_query(self) -> SelectStmt | UnionStmt:
        """Parse SELECT with optional UNION chain."""
        left = self.parse_select()
        if self.tokens.match(TokenType.UNION):
            all_ = self.tokens.match(TokenType.ALL) is not None
            if not self.tokens.check(TokenType.SELECT):
                self._error_current("Expected SELECT after UNION")
            right = self.parse_query()
            return UnionStmt(left=left, right=right, all=all_)
        return left

    def parse_select(self) -> SelectStmt:
        self._expect(TokenType.SELECT)
        distinct = self.tokens.match(TokenType.DISTINCT) is not None

        columns = self._parse_select_list()
        stmt = SelectStmt(columns=columns, distinct=distinct)

        if self.tokens.match(TokenType.FROM):
            stmt.from_table = self._parse_table_ref()
            stmt.joins = self._parse_joins()

        if self.tokens.match(TokenType.WHERE):
            stmt.where = WhereClause(self.parse_expression())

        if self._match_group_by():
            stmt.group_by = GroupByClause(self._parse_expression_list())

        if self.tokens.match(TokenType.HAVING):
            stmt.having = HavingClause(self.parse_expression())

        if self._match_order_by():
            stmt.order_by = OrderByClause(self._parse_order_by_items())

        if self.tokens.match(TokenType.LIMIT):
            stmt.limit = LimitClause(limit=self._parse_int_literal("LIMIT"))

        if self.tokens.match(TokenType.OFFSET):
            offset = self._parse_int_literal("OFFSET")
            if stmt.limit is None:
                stmt.limit = LimitClause(limit=-1, offset=offset)
            else:
                stmt.limit.offset = offset

        return stmt

    def parse_insert(self) -> InsertStmt:
        self._expect(TokenType.INSERT)
        self._expect(TokenType.INTO)
        table = self._parse_table_ref(allow_alias=False)
        columns: list[str] = []
        if self.tokens.match(TokenType.LPAREN):
            columns = self._parse_identifier_list()
            self._expect(TokenType.RPAREN)

        if self.tokens.match(TokenType.VALUES):
            values: list[list[Expression]] = []
            while True:
                self._expect(TokenType.LPAREN)
                values.append(self._parse_expression_list())
                self._expect(TokenType.RPAREN)
                if not self.tokens.match(TokenType.COMMA):
                    break
            return InsertStmt(table=table, columns=columns, values=values)

        if self.tokens.check(TokenType.SELECT):
            query = self.parse_select()
            return InsertStmt(table=table, columns=columns, select=query)

        self._error_current("Expected VALUES or SELECT in INSERT")

    def parse_update(self) -> UpdateStmt:
        self._expect(TokenType.UPDATE)
        table = self._parse_table_ref()
        self._expect(TokenType.SET)
        assignments = [self._parse_assignment()]
        while self.tokens.match(TokenType.COMMA):
            assignments.append(self._parse_assignment())
        where = None
        if self.tokens.match(TokenType.WHERE):
            where = WhereClause(self.parse_expression())
        return UpdateStmt(table=table, assignments=assignments, where=where)

    def parse_delete(self) -> DeleteStmt:
        self._expect(TokenType.DELETE)
        self._expect(TokenType.FROM)
        table = self._parse_table_ref()
        where = None
        if self.tokens.match(TokenType.WHERE):
            where = WhereClause(self.parse_expression())
        return DeleteStmt(table=table, where=where)

    def parse_create(self) -> CreateTableStmt:
        self._expect(TokenType.CREATE)
        self._expect(TokenType.TABLE)
        if_not_exists = self._match_if_not_exists()
        table = self._parse_table_ref(allow_alias=False)
        self._expect(TokenType.LPAREN)
        columns = [self._parse_column_def()]
        while self.tokens.match(TokenType.COMMA):
            columns.append(self._parse_column_def())
        self._expect(TokenType.RPAREN)
        return CreateTableStmt(table=table, columns=columns, if_not_exists=if_not_exists)

    def parse_drop(self) -> DropTableStmt:
        self._expect(TokenType.DROP)
        self._expect(TokenType.TABLE)
        if_exists = self._match_if_exists()
        table = self._parse_table_ref(allow_alias=False)
        return DropTableStmt(table=table, if_exists=if_exists)

    def parse_expression(self) -> Expression:
        """Parse an expression using SQL-like operator precedence."""
        return self._parse_or()

    def _parse_or(self) -> Expression:
        expr = self._parse_and()
        while self.tokens.match(TokenType.OR):
            expr = BinaryExpr(expr, "OR", self._parse_and())
        return expr

    def _parse_and(self) -> Expression:
        expr = self._parse_not()
        while self.tokens.match(TokenType.AND):
            expr = BinaryExpr(expr, "AND", self._parse_not())
        return expr

    def _parse_not(self) -> Expression:
        if self.tokens.match(TokenType.NOT):
            return UnaryExpr("NOT", self._parse_not())
        return self._parse_comparison()

    def _parse_comparison(self) -> Expression:
        expr = self._parse_additive()
        while True:
            tok = self.tokens.current()
            if tok.type == TokenType.OPERATOR and tok.value in {"=", "!=", "<>", "<", "<=", ">", ">="}:
                self.tokens.advance()
                expr = BinaryExpr(expr, tok.value, self._parse_additive())
            elif self.tokens.match(TokenType.IN):
                expr = self._parse_in_expr(expr, negated=False)
            elif self.tokens.match(TokenType.BETWEEN):
                expr = self._parse_between_expr(expr, negated=False)
            elif self.tokens.match(TokenType.LIKE):
                expr = LikeExpr(expr, self._parse_additive(), negated=False)
            elif self.tokens.match(TokenType.IS):
                expr = self._parse_is_expr(expr)
            elif self.tokens.check(TokenType.NOT) and self.tokens.peek(1).type in {
                TokenType.IN,
                TokenType.BETWEEN,
                TokenType.LIKE,
            }:
                self.tokens.advance()
                if self.tokens.match(TokenType.IN):
                    expr = self._parse_in_expr(expr, negated=True)
                elif self.tokens.match(TokenType.BETWEEN):
                    expr = self._parse_between_expr(expr, negated=True)
                else:
                    self._expect(TokenType.LIKE)
                    expr = LikeExpr(expr, self._parse_additive(), negated=True)
            else:
                return expr

    def _parse_additive(self) -> Expression:
        expr = self._parse_multiplicative()
        while self._match_operator("+", "-", "||"):
            op = self.tokens.peek(-1).value
            expr = BinaryExpr(expr, op, self._parse_multiplicative())
        return expr

    def _parse_multiplicative(self) -> Expression:
        expr = self._parse_unary()
        while True:
            if self.tokens.match(TokenType.STAR):
                expr = BinaryExpr(expr, "*", self._parse_unary())
            elif self._match_operator("/", "%"):
                op = self.tokens.peek(-1).value
                expr = BinaryExpr(expr, op, self._parse_unary())
            else:
                return expr

    def _parse_unary(self) -> Expression:
        tok = self.tokens.current()
        if tok.type == TokenType.OPERATOR and tok.value in {"+", "-", "!"}:
            self.tokens.advance()
            return UnaryExpr(tok.value, self._parse_unary())
        expr = self._parse_primary()
        return self._parse_postfix(expr)

    def _parse_primary(self) -> Expression:
        tok = self.tokens.current()

        if tok.type == TokenType.NUMBER:
            self.tokens.advance()
            return LiteralExpr(int(tok.value), "integer")

        if tok.type == TokenType.FLOAT:
            self.tokens.advance()
            return LiteralExpr(float(tok.value), "float")

        if tok.type == TokenType.STRING:
            self.tokens.advance()
            return LiteralExpr(tok.value, "string")

        if tok.type == TokenType.TRUE:
            self.tokens.advance()
            return LiteralExpr(True, "boolean")

        if tok.type == TokenType.FALSE:
            self.tokens.advance()
            return LiteralExpr(False, "boolean")

        if tok.type == TokenType.NULL:
            self.tokens.advance()
            return LiteralExpr(None, "null")

        if tok.type == TokenType.STAR:
            self.tokens.advance()
            return StarExpr()

        if tok.type == TokenType.CASE:
            return self._parse_case()

        if tok.type == TokenType.EXISTS:
            return self._parse_exists()

        if tok.type == TokenType.LPAREN:
            return self._parse_parenthesized()

        if tok.type == TokenType.IDENTIFIER:
            return self._parse_identifier_expr()

        self._error_current("Expected expression")

    def _parse_postfix(self, expr: Expression) -> Expression:
        while self.tokens.match(TokenType.OVER):
            if not isinstance(expr, FunctionCall | AggregateExpr):
                self._error_previous("OVER can only follow a function call")
            expr = self._parse_window_expr(expr)
        return expr

    def _parse_identifier_expr(self) -> Expression:
        first = self._expect_identifier("identifier").value

        if self.tokens.match(TokenType.LPAREN):
            return self._finish_function_call(first)

        if self.tokens.match(TokenType.DOT):
            if self.tokens.match(TokenType.STAR):
                return StarExpr(table=first)
            name = self._expect_identifier("column name").value
            return ColumnRef(name=name, table=first)

        return ColumnRef(name=first)

    def _finish_function_call(self, name: str) -> FunctionCall | AggregateExpr:
        distinct = self.tokens.match(TokenType.DISTINCT) is not None
        args: list[Expression] = []
        if not self.tokens.check(TokenType.RPAREN):
            args = self._parse_expression_list()
        self._expect(TokenType.RPAREN)

        upper_name = name.upper()
        if upper_name in self._AGGREGATES:
            arg = args[0] if args else None
            if len(args) > 1:
                self._error_previous(f"{upper_name} accepts at most one argument")
            return AggregateExpr(function=upper_name, arg=arg, distinct=distinct)
        return FunctionCall(name=name, args=args, distinct=distinct)

    def _parse_parenthesized(self) -> Expression:
        self._expect(TokenType.LPAREN)
        if self.tokens.check(TokenType.SELECT):
            query = self.parse_select()
            self._expect(TokenType.RPAREN)
            return SubqueryExpr(query)
        expr = self.parse_expression()
        self._expect(TokenType.RPAREN)
        return expr

    def _parse_case(self) -> CaseExpr:
        self._expect(TokenType.CASE)
        operand = None
        if not self.tokens.check(TokenType.WHEN):
            operand = self.parse_expression()

        when_clauses: list[WhenClause] = []
        while self.tokens.match(TokenType.WHEN):
            condition = self.parse_expression()
            self._expect(TokenType.THEN)
            result = self.parse_expression()
            when_clauses.append(WhenClause(condition=condition, result=result))

        if not when_clauses:
            self._error_current("CASE requires at least one WHEN clause")

        else_expr = None
        if self.tokens.match(TokenType.ELSE):
            else_expr = self.parse_expression()
        self._expect(TokenType.END)
        return CaseExpr(operand=operand, when_clauses=when_clauses, else_expr=else_expr)

    def _parse_exists(self) -> ExistsExpr:
        self._expect(TokenType.EXISTS)
        self._expect(TokenType.LPAREN)
        query = self.parse_select()
        self._expect(TokenType.RPAREN)
        return ExistsExpr(SubqueryExpr(query))

    def _parse_in_expr(self, expr: Expression, negated: bool) -> InExpr:
        self._expect(TokenType.LPAREN)
        if self.tokens.check(TokenType.SELECT):
            query = self.parse_select()
            self._expect(TokenType.RPAREN)
            return InExpr(expr, SubqueryExpr(query), negated=negated)
        values = self._parse_expression_list()
        self._expect(TokenType.RPAREN)
        return InExpr(expr, values, negated=negated)

    def _parse_between_expr(self, expr: Expression, negated: bool) -> BetweenExpr:
        low = self._parse_additive()
        self._expect(TokenType.AND)
        high = self._parse_additive()
        return BetweenExpr(expr=expr, low=low, high=high, negated=negated)

    def _parse_is_expr(self, expr: Expression) -> Expression:
        negated = self.tokens.match(TokenType.NOT) is not None
        if self.tokens.match(TokenType.NULL):
            return IsNullExpr(expr=expr, negated=negated)
        right = self._parse_additive()
        operator = "IS NOT" if negated else "IS"
        return BinaryExpr(expr, operator, right)

    def _parse_window_expr(self, function: FunctionCall | AggregateExpr) -> WindowExpr:
        self._expect(TokenType.LPAREN)
        partition_by: list[Expression] = []
        order_by: list[OrderByItem] | None = None
        frame = None

        if self.tokens.match(TokenType.PARTITION):
            self._expect(TokenType.BY)
            partition_by = self._parse_expression_list()

        if self._match_order_by():
            order_by = self._parse_order_by_items()

        if self.tokens.check(TokenType.ROWS, TokenType.RANGE):
            frame = self._parse_window_frame()

        self._expect(TokenType.RPAREN)
        return WindowExpr(function=function, partition_by=partition_by, order_by=order_by, frame=frame)

    def _parse_window_frame(self) -> WindowFrame:
        mode = self.tokens.advance().value.upper()
        if self.tokens.match(TokenType.BETWEEN):
            start = self._parse_frame_bound()
            self._expect(TokenType.AND)
            end = self._parse_frame_bound()
            return WindowFrame(mode=mode, start=start, end=end)
        return WindowFrame(mode=mode, start=self._parse_frame_bound())

    def _parse_frame_bound(self) -> FrameBound:
        if self.tokens.match(TokenType.UNBOUNDED):
            if self.tokens.match(TokenType.PRECEDING):
                return FrameBound("UNBOUNDED PRECEDING")
            if self.tokens.match(TokenType.FOLLOWING):
                return FrameBound("UNBOUNDED FOLLOWING")
            self._error_current("Expected PRECEDING or FOLLOWING after UNBOUNDED")

        if self.tokens.match(TokenType.CURRENT):
            self._expect(TokenType.ROW)
            return FrameBound("CURRENT ROW")

        offset = self._parse_int_literal("window frame offset")
        if self.tokens.match(TokenType.PRECEDING):
            return FrameBound("N PRECEDING", offset=offset)
        if self.tokens.match(TokenType.FOLLOWING):
            return FrameBound("N FOLLOWING", offset=offset)
        self._error_current("Expected PRECEDING or FOLLOWING in window frame bound")

    def _parse_select_list(self) -> list[Expression]:
        columns = [self._parse_select_item()]
        while self.tokens.match(TokenType.COMMA):
            columns.append(self._parse_select_item())
        return columns

    def _parse_select_item(self) -> Expression:
        expr = self.parse_expression()
        alias = None
        if self.tokens.match(TokenType.AS):
            alias = self._expect_identifier("alias").value
        elif self._can_start_implicit_alias():
            alias = self.tokens.advance().value
        if alias is not None:
            return AliasExpr(expr=expr, alias=alias)
        return expr

    def _parse_table_ref(self, allow_alias: bool = True) -> TableRef:
        first = self._expect_identifier("table name").value
        schema = None
        name = first
        if self.tokens.match(TokenType.DOT):
            schema = first
            name = self._expect_identifier("table name").value

        alias = None
        if allow_alias:
            if self.tokens.match(TokenType.AS):
                alias = self._expect_identifier("table alias").value
            elif self._can_start_table_alias():
                alias = self.tokens.advance().value

        return TableRef(name=name, alias=alias, schema=schema)

    def _parse_joins(self) -> list[JoinClause]:
        joins: list[JoinClause] = []
        while True:
            join_type = self._match_join_type()
            if join_type is None:
                return joins

            table = self._parse_table_ref()
            condition = None
            if self.tokens.match(TokenType.ON):
                condition = self.parse_expression()
            elif join_type != "CROSS":
                self._error_current("Expected ON clause for JOIN")
            joins.append(JoinClause(join_type=join_type, table=table, condition=condition))

    def _match_join_type(self) -> str | None:
        if self.tokens.match(TokenType.JOIN):
            return "INNER"
        if self.tokens.match(TokenType.INNER):
            self._expect(TokenType.JOIN)
            return "INNER"
        if self.tokens.match(TokenType.LEFT):
            self.tokens.match(TokenType.OUTER)
            self._expect(TokenType.JOIN)
            return "LEFT"
        if self.tokens.match(TokenType.RIGHT):
            self.tokens.match(TokenType.OUTER)
            self._expect(TokenType.JOIN)
            return "RIGHT"
        if self.tokens.match(TokenType.FULL):
            self.tokens.match(TokenType.OUTER)
            self._expect(TokenType.JOIN)
            return "FULL"
        if self.tokens.match(TokenType.CROSS):
            self._expect(TokenType.JOIN)
            return "CROSS"
        return None

    def _parse_assignment(self) -> Assignment:
        column = self._parse_column_name()
        self._expect_operator("=")
        return Assignment(column=column, value=self.parse_expression())

    def _parse_column_def(self) -> ColumnDef:
        name = self._expect_identifier("column name").value
        data_type = self._parse_data_type()
        nullable = True
        primary_key = False
        default = None

        while not self.tokens.check(TokenType.COMMA, TokenType.RPAREN, TokenType.EOF):
            if self.tokens.check(TokenType.IDENTIFIER) and self.tokens.current().value.upper() == "PRIMARY":
                self.tokens.advance()
                self._expect_word("KEY")
                primary_key = True
            elif self.tokens.match(TokenType.NOT):
                self._expect(TokenType.NULL)
                nullable = False
            elif self.tokens.match(TokenType.NULL):
                nullable = True
            elif self.tokens.check(TokenType.IDENTIFIER) and self.tokens.current().value.upper() == "DEFAULT":
                self.tokens.advance()
                default = self.parse_expression()
            else:
                self._error_current("Expected column constraint")

        return ColumnDef(
            name=name,
            data_type=data_type,
            nullable=nullable,
            primary_key=primary_key,
            default=default,
        )

    def _parse_data_type(self) -> str:
        tok = self.tokens.current()
        if tok.type not in {TokenType.IDENTIFIER, TokenType.NUMBER}:
            self._error_current("Expected column data type")

        parts = [self.tokens.advance().value]
        if self.tokens.match(TokenType.LPAREN):
            inner: list[str] = []
            while not self.tokens.check(TokenType.RPAREN, TokenType.EOF):
                inner.append(self.tokens.advance().value)
            self._expect(TokenType.RPAREN)
            parts.append("(" + "".join(inner) + ")")
        return "".join(parts)

    def _parse_order_by_items(self) -> list[OrderByItem]:
        items = [self._parse_order_by_item()]
        while self.tokens.match(TokenType.COMMA):
            items.append(self._parse_order_by_item())
        return items

    def _parse_order_by_item(self) -> OrderByItem:
        expr = self.parse_expression()
        ascending = True
        nulls_first = None
        if self.tokens.match(TokenType.ASC):
            ascending = True
        elif self.tokens.match(TokenType.DESC):
            ascending = False

        if self.tokens.check(TokenType.NULL) and self.tokens.current().value.upper() == "NULLS":
            self.tokens.advance()
            if self._match_word("FIRST"):
                nulls_first = True
            elif self._match_word("LAST"):
                nulls_first = False
            else:
                self._error_current("Expected FIRST or LAST after NULLS")

        return OrderByItem(expr=expr, ascending=ascending, nulls_first=nulls_first)

    def _parse_expression_list(self) -> list[Expression]:
        values = [self.parse_expression()]
        while self.tokens.match(TokenType.COMMA):
            values.append(self.parse_expression())
        return values

    def _parse_identifier_list(self) -> list[str]:
        values = [self._expect_identifier("identifier").value]
        while self.tokens.match(TokenType.COMMA):
            values.append(self._expect_identifier("identifier").value)
        return values

    def _parse_column_name(self) -> str:
        first = self._expect_identifier("column name").value
        if self.tokens.match(TokenType.DOT):
            second = self._expect_identifier("column name").value
            return f"{first}.{second}"
        return first

    def _match_group_by(self) -> bool:
        if self.tokens.match(TokenType.GROUP_BY):
            return True
        pos = self.tokens.save()
        if self.tokens.match(TokenType.GROUP) and self.tokens.match(TokenType.BY):
            return True
        self.tokens.restore(pos)
        return False

    def _match_order_by(self) -> bool:
        if self.tokens.match(TokenType.ORDER_BY):
            return True
        pos = self.tokens.save()
        if self.tokens.match(TokenType.ORDER) and self.tokens.match(TokenType.BY):
            return True
        self.tokens.restore(pos)
        return False

    def _match_if_not_exists(self) -> bool:
        pos = self.tokens.save()
        if self._match_word("IF") and self.tokens.match(TokenType.NOT) and self.tokens.match(TokenType.EXISTS):
            return True
        self.tokens.restore(pos)
        return False

    def _match_if_exists(self) -> bool:
        pos = self.tokens.save()
        if self._match_word("IF") and self.tokens.match(TokenType.EXISTS):
            return True
        self.tokens.restore(pos)
        return False

    def _match_operator(self, *operators: str) -> bool:
        tok = self.tokens.current()
        if tok.type == TokenType.OPERATOR and tok.value in operators:
            self.tokens.advance()
            return True
        return False

    def _expect_operator(self, operator: str) -> Token:
        tok = self.tokens.current()
        if tok.type == TokenType.OPERATOR and tok.value == operator:
            return self.tokens.advance()
        self._error_current(f"Expected operator {operator!r}")

    def _match_word(self, word: str) -> bool:
        tok = self.tokens.current()
        if tok.type == TokenType.IDENTIFIER and tok.value.upper() == word:
            self.tokens.advance()
            return True
        return False

    def _expect_word(self, word: str) -> Token:
        tok = self.tokens.current()
        if tok.type == TokenType.IDENTIFIER and tok.value.upper() == word:
            return self.tokens.advance()
        self._error_current(f"Expected {word}")

    def _expect_identifier(self, description: str) -> Token:
        tok = self.tokens.current()
        if tok.type == TokenType.IDENTIFIER:
            return self.tokens.advance()
        self._error_current(f"Expected {description}")

    def _expect(self, token_type: TokenType) -> Token:
        tok = self.tokens.current()
        if tok.type == token_type:
            return self.tokens.advance()
        self._error_current(f"Expected {token_type.name}")

    def _parse_int_literal(self, description: str) -> int:
        tok = self.tokens.current()
        if tok.type != TokenType.NUMBER:
            self._error_current(f"Expected integer literal for {description}")
        self.tokens.advance()
        return int(tok.value)

    def _can_start_implicit_alias(self) -> bool:
        tok = self.tokens.current()
        return tok.type == TokenType.IDENTIFIER and tok.type not in self._CLAUSE_STARTERS

    def _can_start_table_alias(self) -> bool:
        tok = self.tokens.current()
        if tok.type != TokenType.IDENTIFIER:
            return False
        upper = tok.value.upper()
        return upper not in {"ON", "WHERE", "GROUP", "ORDER", "HAVING", "LIMIT", "OFFSET"}

    def _error_current(self, message: str) -> None:
        tok = self.tokens.current()
        raise ParseError(f"{message}, got {tok.type.name} ({tok.value!r})", tok.line, tok.col)

    def _error_previous(self, message: str) -> None:
        tok = self.tokens.peek(-1)
        raise ParseError(message, tok.line, tok.col)


def parse(query: str) -> Statement:
    """Parse a SQL query string into an AST statement."""
    return Parser(query).parse()
